278:  */
279: static size_t cookiehash(const char * const domain)
280: {
281:   const char *top;
282:   size_t len;
283: 
284:   if(!domain || Curl_host_is_ipnum(domain))
285:     return 0;
286: 
287:   top = get_top_domain(domain, &len);
288:   return cookie_hash_domain(top, len);
289: }
