1386:   struct Cookie *co;
1387:   struct Cookie *mainco = NULL;
1388:   size_t matches = 0;
1389:   bool is_ip;
1390:   const size_t myhash = cookiehash(host);
1391: 
1392:   if(!c || !c->cookies[myhash])
1393:     return NULL; /* no cookie struct or no cookies in the struct */
