1395:   /* at first, remove expired cookies */
1396:   remove_expired(c);
1397: 
1398:   /* check if host is an IP(v4|v6) address */
1399:   is_ip = Curl_host_is_ipnum(host);
1400: 
1401:   co = c->cookies[myhash];
