1621:                               struct CookieInfo *c, const char *filename)
1622: {
1623:   struct Cookie *co;
1624:   FILE *out = NULL;
1625:   bool use_stdout = FALSE;
1626:   char *tempstore = NULL;
1627:   CURLcode error = CURLE_OK;
