1629:   if(!c)
1630:     /* no cookie engine alive */
1631:     return CURLE_OK;
1632: 
1633:   /* at first, remove expired cookies */
1634:   remove_expired(c);
1635: 
1636:   if(!strcmp("-", filename)) {
1637:     /* use stdout */
1638:     out = stdout;
1639:     use_stdout = TRUE;
